+    expect(onAudio).toHaveBeenCalledTimes(1);
+    expect(onAudio.mock.calls[0]?.[0]).toBeInstanceOf(Buffer);
+    expect(onAudio.mock.calls[0]?.[0]).toHaveLength(80);
